insert into knowledge_base_files (id, business_id, name, file_url, mime_type, size_bytes, extracted_text, status, created_at) values
  ('00000000-0000-4000-8000-a50000000001', '00000000-0000-4000-8000-b10000000001', 'Return & Refund Policy.pdf', null, 'application/pdf', 40000, 'Vyuha Home Store return and refund policy. Customers may return furniture within 7 days of delivery if unused and in original packaging. Custom or made-to-order pieces are non-returnable. Refunds are issued to the original payment method within 5 business days of inspection. Damaged-on-arrival items are replaced free of charge if reported within 48 hours with photos. Delivery fees are non-refundable except for our error.', 'ready', '2026-06-01T07:30:00.000Z'),
  ('00000000-0000-4000-8000-a50000000002', '00000000-0000-4000-8000-b10000000001', 'Warranty Terms.pdf', null, 'application/pdf', 52500, 'All solid-wood furniture carries a 3-year warranty against manufacturing defects including joint failure, warping and hardware breakage. Upholstered items carry a 1-year warranty on frames and 6 months on fabric. Lighting products carry a 1-year electrical warranty. The warranty does not cover normal wear, water damage, or improper assembly by third parties. Claims require the original invoice number.', 'ready', '2026-06-15T07:30:00.000Z'),
  ('00000000-0000-4000-8000-a50000000003', '00000000-0000-4000-8000-b10000000001', 'Store Operations Handbook.docx', null, 'application/vnd.openxmlformats-officedocument.wordprocessingml.document', 65000, 'Store hours are 10:00 to 20:30, Monday through Saturday; closed Sundays. Opening checklist: lights, POS float of 5,000 rupees, display dusting, stock of the day board. Deliveries within Bengaluru are free above 25,000 rupees, otherwise 800 rupees flat. EMI is available on purchases above 20,000 rupees through Bajaj Finserv and all major credit cards. Bulk and trade orders above 1 lakh rupees require a 40 percent advance.', 'ready', '2026-06-13T07:30:00.000Z'),
  ('00000000-0000-4000-8000-a50000000004', '00000000-0000-4000-8000-b10000000001', 'Supplier Onboarding Checklist.pdf', null, 'application/pdf', 77500, 'New supplier onboarding requires: GSTIN certificate, cancelled cheque, two trade references, sample approval by the store manager, and signed rate contract valid for 12 months. Payment terms default to net 30 from goods receipt. Quality rejections above 4 percent in a quarter trigger a supplier review.', 'ready', '2026-05-22T07:30:00.000Z');
